package main

import (
	"context"
	"fmt"
	"time"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	// connect to your Atlas cluster
	client, err := mongo.Connect(options.Client().ApplyURI("<connection-string"))
	if err != nil {
		panic(err)
	}
	defer client.Disconnect(context.TODO())

	// set namespace
	collection := client.Database("sample_mflix").Collection("movies")

	// define pipeline stages
	searchStage := bson.D{{Key: "$search", Value: bson.M{
		"index": "default",
		"compound": bson.M{
			"filter": bson.A{
				bson.M{
					"wildcard": bson.D{
						{Key: "path", Value: "title"},
						{Key: "query", Value: "Summer*"},
					}},
			},
			"must": bson.A{
				bson.M{
					"near": bson.M{
						"path":   "released",
						"origin": time.Date(2014, time.April, 18, 0, 0, 0, 0, time.UTC),
						"pivot":  13149000000}},
			},
		},
		"sort": bson.D{{Key: "released", Value: -1}},
	}}}

	limitStage := bson.D{{Key: "$limit", Value: 5}}
	projectStage := bson.D{{Key: "$project", Value: bson.D{{Key: "_id", Value: 0}, {Key: "title", Value: 1}, {Key: "released", Value: 1}, {Key: "score", Value: bson.D{{Key: "$meta", Value: "searchScore"}}}}}}

	// run pipeline
	cursor, err := collection.Aggregate(context.TODO(), mongo.Pipeline{searchStage, limitStage, projectStage})
	if err != nil {
		panic(err)
	}

	// print results
	var results []bson.D
	if err = cursor.All(context.TODO(), &results); err != nil {
		panic(err)
	}
	for _, result := range results {
		fmt.Println(result)
	}
}

import java.util.Arrays;
import java.util.List;

import static com.mongodb.client.model.Aggregates.limit;
import static com.mongodb.client.model.Aggregates.project;
import static com.mongodb.client.model.Projections.*;
import com.mongodb.client.MongoClient;
import com.mongodb.client.MongoClients;
import com.mongodb.client.MongoCollection;
import com.mongodb.client.MongoDatabase;
import org.bson.Document;

import java.time.Instant;
import java.util.Date;

public class SortByDate {
  public static void main( String[] args ) {
    // define query
	    Document agg =
	        new Document("$search", 
	        	    new Document("index", "default")
	                .append("compound", 
	        new Document("filter", Arrays.asList(new Document("wildcard", 
	                        new Document("query", "Summer*")
	                                .append("path", "title"))))
	                    .append("must", Arrays.asList(new Document("near", 
	                        new Document("pivot", 13149000000L)
	                                .append("path", "released")
	                                .append("origin", Date.from(Instant.parse("2014-04-18T00:00:00.000+00:00")))))))
	                .append("sort", new Document("released", -1)));

    // specify connection
    String uri = "<connection-string>";

    // establish connection and set namespace
    try (MongoClient mongoClient = MongoClients.create(uri)) {
      MongoDatabase database = mongoClient.getDatabase("sample_mflix");
      MongoCollection<Document> collection = database.getCollection("movies");
	  // run query and print results
      collection.aggregate(Arrays.asList(agg, 
        limit(5), 
        project(fields(exclude("_id"), include("title"), include("released"), computed("score", new Document("$meta", "searchScore"))))))
        .forEach(doc -> System.out.println(doc.toJson()));	
    }
  }
}

